#include <stdio.h>
#include <string.h>
int main() {
    int t = 1;
    if (scanf("%d", &t) != 1) t = 1; // default to 1 if no valid input
    const char *ans = "Class: a blueprint that defines attributes and methods. Instance Object: a concrete object created from the class; it contains its own data (instance attributes) and can use the class's methods. Method Object: the function defined inside a class; when accessed through an instance it becomes a bound method, which carries the instance as its first argument (self). When a method is called on an instance, Python performs attribute lookup, creates a bound method object linking the instance to the function, then invokes the function with the instance automatically passed as the first parameter, allowing the method to operate on that particular object's state.";
    for (int i = 0; i < t; ++i) {
        printf("%s\n", ans);
    }
    return 0;
}

